  CLASS
	NAME "Evapotranspiración real (mm)"
    EXPRESSION ([pixel] = -99999)
    COLOR -1 -1 -1
  END
  CLASS
	NAME "31 - 40"
    EXPRESSION ([pixel] >= 31 AND [pixel] < 40)
    COLOR 54 145 33
  END
  CLASS
	NAME "40 - 50"
    EXPRESSION ([pixel] >= 40 AND [pixel] < 50)
    COLOR 149 199 105
  END
  CLASS
	NAME "50 - 60"
    EXPRESSION ([pixel] >= 50 AND [pixel] < 60)
    COLOR 102 217 129
  END
  CLASS
	NAME "60 - 80"
    EXPRESSION ([pixel] >= 60 AND [pixel] < 80)
    COLOR 204 230 76
  END
  CLASS
	NAME "80 - 100"
    EXPRESSION ([pixel] >= 80 AND [pixel] < 100)
    COLOR 235 255 153
  END
  CLASS
	NAME "100 - 110"
    EXPRESSION ([pixel] >= 100 AND [pixel] < 110)
    COLOR 250 250 95
  END
  CLASS
	NAME "110 - 120"
    EXPRESSION ([pixel] >= 110 AND [pixel] < 120)
    COLOR 255 208 0
  END
  CLASS
	NAME "120 - 130"
    EXPRESSION ([pixel] >= 120 AND [pixel] < 130)
    COLOR 255 134 128
  END
  CLASS
	NAME "130 - 132"
    EXPRESSION ([pixel] >= 130 AND [pixel] <= 150)
    COLOR 230 101 127
  END
END # Layer